(function($) {
'use strict';
var VH360GalleryAdmin = {
frame: null,
sortable: null,
init: function() {
this.bindEvents();
this.initSortable();
},
bindEvents: function() {
var self = this;
$(document).on('click', '#vh360-gallery-add-images', function(e) {
e.preventDefault();
self.openMediaFrame();
});
$(document).on('click', '.vh360-gallery-image-remove', function(e) {
e.preventDefault();
$(this).closest('.vh360-gallery-image-item').remove();
});
},
initSortable: function() {
var container = document.getElementById('vh360-gallery-images-container');
if (!container) {
return;
}
if (typeof Sortable !== 'undefined') {
this.sortable = Sortable.create(container, {
animation: 150,
ghostClass: 'sortable-ghost',
handle: '.vh360-gallery-image-item'
});
} else {
if ($.fn.sortable) {
$(container).sortable({
placeholder: 'sortable-ghost',
cursor: 'move'
});
}
}
},
openMediaFrame: function() {
var self = this;
if (this.frame) {
this.frame.open();
return;
}
this.frame = wp.media({
title: vh360GalleryAdmin.i18n.selectImages,
button: {
text: vh360GalleryAdmin.i18n.addToGallery
},
library: {
type: 'image'
},
multiple: true
});
this.frame.on('select', function() {
var selection = self.frame.state().get('selection');
selection.each(function(attachment) {
self.addImage(attachment.toJSON());
});
});
this.frame.open();
},
addImage: function(attachment) {
var container = $('#vh360-gallery-images-container');
if (container.find('[data-id="' + attachment.id + '"]').length > 0) {
return;
}
var thumbUrl = attachment.sizes && attachment.sizes.thumbnail
? attachment.sizes.thumbnail.url
: attachment.url;
var itemHtml = '<div class="vh360-gallery-image-item" data-id="' + attachment.id + '">' +
'<img src="' + thumbUrl + '" alt="">' +
'<button type="button" class="vh360-gallery-image-remove" aria-label="' + vh360GalleryAdmin.i18n.removeImage + '">&times;</button>' +
'<input type="hidden" name="vh360_gallery_images[]" value="' + attachment.id + '">' +
'</div>';
container.append(itemHtml);
}
};
$(document).ready(function() {
VH360GalleryAdmin.init();
});
})(jQuery);
